import{_ as n}from"./plugin-vue_export-helper-c27b6911.js";import{r as s,o as l,c as i,a as e,b as r,d as o,e as a}from"./app-706bfe03.js";const p={},c=a('<h1 id="欧几里得几何与非欧几何" tabindex="-1"><a class="header-anchor" href="#欧几里得几何与非欧几何" aria-hidden="true">#</a> 欧几里得几何与非欧几何</h1><p>欧几里得几何是按照欧几里得的《几何原本》构造的几何学。</p><p>欧几里得几何通常指二维平面上的几何，即<strong>平面几何</strong>。三维空间的欧几里得几何通常称为<strong>立体几何</strong>。</p><p>《几何原本》共分 13 卷，包含了平面几何、数论、无理数、立体几何等内容。1-6 卷的内容主要为平面几何，其中提出了五条公理（公设）：</p><blockquote><ol><li>从一点向另一点可以引一条直线。</li><li>任意线段能无限延伸成一条直线。</li><li>给定任意线段，可以以其一个端点作为圆心，该线段作为半径作一个圆。</li><li>所有直角都相等。</li><li>若两条直线都与第三条直线相交，并且在同一边的内角之和小于两个直角，则这两条直线在这一边必定相交。</li></ol></blockquote><p>第五条称为<strong>欧几里得第五公设</strong>，又称<strong>平行公设</strong>。</p><img src="https://raw.githubusercontent.com/yamsfeer/pic-bed/master/e6c9d24egy1h3bdhabkkbj20jg0eldfy.jpg" style="zoom:45%;"><p>平行公设后来引申出了很多等价命题，比如：</p><blockquote><p>三角形内角和为两直角。</p></blockquote><p>更重要的一条等价于平行公设的公理是<strong>普莱费尔公理</strong>：</p><blockquote><p>通过直线外一点，有且仅有一条直线与之平行</p></blockquote><p>根据这个公理的不同情况，发展出了<strong>非欧几何</strong>。非欧几何与欧几里得几何最大的不同在于平行公设。</p><p>按几何特性（曲率），现存非欧几何的类型可以概括如下：</p><ul><li>坚持第五公设，引出<strong>欧几里得几何</strong>。</li><li>以“可以引最少两条平行线”为新公设，引出<strong>罗氏几何</strong>（双曲几何）。</li><li>以“一条平行线也不能引”为新公设，引出<strong>黎曼几何</strong>（椭圆几何）。</li></ul><p>这三种几何学，都是常曲率空间中的几何学，分别对应曲率为0、负常数和正常数的情况。</p><p><img src="https://raw.githubusercontent.com/yamsfeer/pic-bed/master/e6c9d24egy1h3bbek88o3j20i00b3q3m.jpg" alt=""></p><p>欧几里得几何三角形的内角和是 180 度，黎曼几何内角和大于 180 度，双曲几何则小于 180 度。</p><p>如果完全去掉第五公设，就得到更加一般化的<strong>绝对几何</strong>。这种几何不仅可以囊括前面提到的三种几何，而且允许空间的不同位置有不同的曲率。</p><p>黎曼几何是描述任意维数任意弯曲的绝对几何空间的一种微分解析几何学。</p><img src="https://raw.githubusercontent.com/yamsfeer/pic-bed/master/e6c9d24egy1h3bct6kewdj20nw08kjs7.jpg" style="zoom:67%;"><p>一般来讲，非欧几何有广义、狭义、通常意义三个不同含义：</p><ul><li>广义的非欧几何：泛指一切和欧几里得几何不同的几何学。</li><li>狭义的非欧几何：只是指罗氏几何或黎曼几何。</li><li>通常意义的非欧几何：指罗氏几何和黎曼几何二者。</li></ul><h2 id="参考" tabindex="-1"><a class="header-anchor" href="#参考" aria-hidden="true">#</a> 参考</h2>',23),g={href:"https://zh.wikipedia.org/wiki/%E9%9D%9E%E6%AC%A7%E5%87%A0%E9%87%8C%E5%BE%97%E5%87%A0%E4%BD%95",target:"_blank",rel:"noopener noreferrer"},h={href:"https://zh.wikipedia.org/wiki/%E5%B9%B3%E8%A1%8C%E5%85%AC%E8%A8%AD",target:"_blank",rel:"noopener noreferrer"},_={href:"https://www.163.com/dy/article/ENP3KI0G053299CD.html",target:"_blank",rel:"noopener noreferrer"};function d(m,u){const t=s("ExternalLinkIcon");return l(),i("div",null,[c,e("p",null,[e("a",g,[r("非欧几里得几何--维基百科"),o(t)])]),e("p",null,[e("a",h,[r("平行公设--维基百科"),o(t)])]),e("p",null,[e("a",_,[r("并不神秘的非欧几何，它究竟讲的是什么？今天带你搞懂"),o(t)])])])}const f=n(p,[["render",d],["__file","欧几里得几何与非欧几何.html.vue"]]);export{f as default};
